style.css:
@import url("https://fonts.googleapis.com/css2?family=Aboreto&display=swap");
* {
  box-sizing: border-box;
}

html {
  font-size: 6.25vmax;
}
@media (max-width: 992px) {
  html {
    font-size: 60px;
  }
}

body {
  min-height: 100vh;
  display: flex;
  justify-content: center;
  align-items: center;
  color: #ececec;
  background-color: #222;
  font-size: 0.3rem;
  font-family: "Aboreto", system-ui;
  perspective: 1500px;
}

.container {
  position: relative;
  width: 4rem;
  aspect-ratio: 1/1;
  transform-style: preserve-3d;
  transform: translate3d(0, 0, -800px);
}

.inner {
  width: 100%;
  height: 100%;
  transform-style: preserve-3d;
  animation: rotate linear 30s infinite;
}

.card-wrapper {
  position: absolute;
  inset: 0;
  margin: auto;
  height: 100%;
  aspect-ratio: 9/16;
  transform-style: preserve-3d;
  backface-visibility: visible;
}
.card-wrapper:nth-child(1) {
  transform: rotateY(45deg) translateX(150%);
}
.card-wrapper:nth-child(2) {
  transform: rotateY(90deg) translateX(150%);
}
.card-wrapper:nth-child(3) {
  transform: rotateY(135deg) translateX(150%);
}
.card-wrapper:nth-child(4) {
  transform: rotateY(180deg) translateX(150%);
}
.card-wrapper:nth-child(5) {
  transform: rotateY(225deg) translateX(150%);
}
.card-wrapper:nth-child(6) {
  transform: rotateY(270deg) translateX(150%);
}
.card-wrapper:nth-child(7) {
  transform: rotateY(315deg) translateX(150%);
}
.card-wrapper:nth-child(8) {
  transform: rotateY(360deg) translateX(150%);
}
.card-wrapper img {
  display: block;
  width: 100%;
  height: 100%;
  border-radius: 36px;
  object-fit: cover;
  filter: grayscale(0.2);
  transform: rotateY(90deg);
}

@keyframes rotate {
  0% {
    transform: rotateY(-50deg) rotateX(12deg) rotateY(0deg);
  }
  100% {
    transform: rotateY(-50deg) rotateX(12deg) rotateY(-360deg);
  }
}
